/// GET v1/signupUrls
/// Creates an enterprise signup URL.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `androidmanagement_signup_urls_create_execute()` to send, or `androidmanagement_signup_urls_create` for simplest API.

pub fn androidmanagement_signup_urls_create_builder(
    client: &SimpleHttpClient,
    adminEmail: Option<&str>,
    allowedDomains: Option<&str>,
    callbackUrl: Option<&str>,
    projectId: Option<&str>,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!("https://androidmanagement.googleapis.com/v1/signupUrls",);

    // Build request
    let mut query_parts = Vec::new();
    if let Some(val) = adminEmail {
        query_parts.push(format!("adminEmail={}", val));
    }
    if let Some(val) = allowedDomains {
        query_parts.push(format!("allowedDomains={}", val));
    }
    if let Some(val) = callbackUrl {
        query_parts.push(format!("callbackUrl={}", val));
    }
    if let Some(val) = projectId {
        query_parts.push(format!("projectId={}", val));
    }

    let url_with_query = if query_parts.is_empty() {
        url
    } else {
        format!("{}?{}", url, query_parts.join("&"))
    };

    let builder = client
        .get(&url_with_query)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?;

    Ok(builder)
}

